inline int getEntryIndex(uint16_t species, uint8_t form) {
    if (species >= 560) return 0;
    if (form == 0 || FORM_COUNT[species] <= 1) return species;
    if (form >= FORM_COUNT[species]) return species;
    uint16_t fsi = FORM_STATS_INDEX[species];
    if (fsi == 0) return species;
    int idx = fsi + form - 1;
    return (idx < 560) ? idx : species;
}

inline uint16_t getAbility(uint16_t species, uint8_t form, int index) {
    int idx = getEntryIndex(species, form);
    const auto& e = ABILITIES[idx];
    if (index == 0) return e.ab0;
    if (index == 1) return e.ab1;
    return e.abH;
}

inline uint8_t getGenderRatio(uint16_t species, uint8_t form) {
    return GENDER_RATIO[getEntryIndex(species, form)];
}

inline uint8_t getBaseFriendship(uint16_t species, uint8_t form) {
    return BASE_FRIENDSHIP[getEntryIndex(species, form)];
}

inline uint8_t getHatchCycles(uint16_t species, uint8_t form) {
    return HATCH_CYCLES[getEntryIndex(species, form)];
}

inline uint8_t getGrowthRate(uint16_t species, uint8_t form) {
    return GROWTH_RATE[getEntryIndex(species, form)];
}

inline BaseStatEntry getBaseStats(uint16_t species, uint8_t form) {
    return BASE_STATS[getEntryIndex(species, form)];
}

