inline bool isPresentInGame(uint16_t species, uint8_t form) {
    if (species >= 560) return false;
    int idx = getEntryIndex(species, form);
    if (idx < 0 || idx >= 560) return false;
    return IS_PRESENT[idx] != 0;
}

